function norm(lang: string | null | undefined): string {
  return lang === 'sl' || lang === 'de' ? lang : 'en';
}

export function pushTitle(messageKey: string, lang: string | null | undefined): string {
  const l = norm(lang);
  return kTitles[l][messageKey] ?? kFallbackTitle[l];
}

export function pushBody(lang: string | null | undefined): string {
  return kFallbackBody[norm(lang)];
}
